<div class="card"><div class="card-body"><?php foreach($fechas as$f):$actual=date('Y-m',strtotime($f['fecha']));if($actual!==$mes):$mes=$actual;?><h2 class="h5 border-bottom pb-2 mt-3"><?=atenea_e(ucfirst($meses[(int)date('n',strtotime($f['fecha']))]).' '.date('Y',strtotime($f['fecha'])))?></h2><?php endif;?><article class="d-flex gap-3 py-3 border-bottom"><time class="aula-date" datetime="<?=atenea_e($f['fecha'])?>"><small><?=strtoupper(date('D',strtotime($f['fecha'])))?></small><strong><?=date('d',strtotime($f['fecha']))?></strong></time><div><span class="badge bg-light text-dark"><?=atenea_e(ucfirst($f['tipo']))?></span><h3 class="h6 mt-2 mb-1"><?=atenea_e($f['titulo'])?></h3><p class="text-muted mb-1"><?=atenea_e($f['descripcion'])?></p><small><?=date('d/m/Y h:i A',strtotime($f['fecha']))?></small><?php if($f['origen']==='contenido'):?> · <a href="<?=atenea_url('src/estudiantes/contenido.php?id='.(int)$f['referencia_id'])?>">Abrir</a><?php endif;?></div></article><?php endforeach;?><?php if(!$fechas):?><div class="aula-empty"><i class="bi bi-calendar2-check"></i><h2 class="h5 mt-3">No hay fechas próximas</h2><p class="mb-0">Las fechas publicadas por docentes aparecerán automáticamente.</p></div><?php endif;?></div></div><?php portalEstudiantePie();
